  if (scores.support >= 0.42) {
    return scores.tenderness >= 0.5 ? "soft-sad" : "soft";
  }
  if (scores.work >= 0.36 && scores.playful >= 0.25) {
    return "serious-playful";
  }
  if (scores.work >= 0.36 || scores.seriousness >= 0.42) {
    return "serious";
  }
