function uniqueStrings(values) {
  return [...new Set(values.filter(Boolean))];
}

function clampUnit(value) {
  const number = Number(value);
  if (!Number.isFinite(number)) {
    return 0;
  }
  return Math.max(0, Math.min(1, number));
}

module.exports = {
  planExpressionPolicy,
  _test: {
    chooseTone,
    buildGuidance
  }
};

