      evidenceEpisodeIds,
      sourceHash,
      generatedBy: previousItem?.sourceHash === sourceHash ? previousItem.generatedBy : "local",
      reviewStatus: previousItem?.sourceHash === sourceHash ? previousItem.reviewStatus : "auto",
      evidenceCount,
      strength,
      confidence,
