const { setIcon } = require("obsidian");

const {
  extractMentionReferences,
  formatMentionToken,
  replaceObsidianOpenLinks
} = __require("src/view/reference/mention.js");
const { MentionMenuController } = __require("src/view/reference/MentionMenuController.js");
